39	class MapBridge(QObject):
40	    """Bridge object registered with QWebChannel for JS ↔ Python calls."""
41	
42	    mapClicked = pyqtSignal(float, float)   # lat, lon
43	    markerClicked = pyqtSignal(int)          # target_id
44	    mapReady = pyqtSignal()
45	
46	    def __init__(self, parent=None):
47	        super().__init__(parent)
48	        self._map_ready = False
49	
50	    @pyqtSlot(float, float)
51	    def onMapClick(self, lat: float, lon: float):
52	        logger.debug(f"Map clicked: {lat}, {lon}")
53	        self.mapClicked.emit(lat, lon)
54	
55	    @pyqtSlot(int)
56	    def onMarkerClick(self, target_id: int):
57	        logger.debug(f"Marker clicked: #{target_id}")
58	        self.markerClicked.emit(target_id)
59	
60	    @pyqtSlot()
61	    def onMapReady(self):
62	        logger.info("Leaflet map ready")
63	        self._map_ready = True
64	        self.mapReady.emit()
65	
66	    @pyqtSlot(str)
67	    def logFromJS(self, message: str):
68	        logger.info(f"[JS] {message}")
69	
70	    @property
71	    def is_ready(self) -> bool:
72	        return self._map_ready
