281	function initMap() {{
282	    map = L.map('map', {{ preferCanvas:true, zoomControl:true }})
283	        .setView([{lat}, {lon}], 10);
284	    setTileServer('osm');
285	
286	    radarMarker = L.circleMarker([{lat},{lon}], {{
287	        radius:12, fillColor:'#FF5252', color:'white',
288	        weight:3, opacity:1, fillOpacity:1
289	    }}).addTo(map);
290	    updateRadarPopup();
