292	    coverageCircle = L.circle([{lat},{lon}], {{
293	        radius:{cov}, color:'#FF5252', fillColor:'#FF5252',
294	        fillOpacity:0.08, weight:2, dashArray:'8, 8'
295	    }}).addTo(map);
296	
297	    addLegend();
298	    map.on('click', function(e){{ if(bridge) bridge.onMapClick(e.latlng.lat,e.latlng.lng); }});
299	}}
