302	    var cfg = tileServers[id]; if(!cfg) return;
303	    if(currentTileLayer) map.removeLayer(currentTileLayer);
304	    currentTileLayer = L.tileLayer(
305	        cfg.url,
306	        {{ attribution:cfg.attribution, maxZoom:cfg.maxZoom }}
