357	function updateRadarPosition(lat,lon,alt,pitch,heading) {{
358	    if(!radarMarker||!coverageCircle) return;
359	    radarMarker.setLatLng([lat,lon]);
360	    coverageCircle.setLatLng([lat,lon]);
