364	function updateTargets(targetsJson) {{
365	    try {{
366	        if(!map) {{
367	            if(bridge) bridge.logFromJS('updateTargets: map not ready yet');
368	            return;
369	        }}
370	        var targets = JSON.parse(targetsJson);
371	        if(bridge) bridge.logFromJS('updateTargets: parsed '+targets.length+' targets');
372	        var currentIds = {{}};
373	
374	        targets.forEach(function(t) {{
375	            currentIds[t.id] = true;
376	            var lat=t.latitude, lon=t.longitude;
377	            var color = getTargetColor(t.velocity);
378	            var radius = Math.max(5, Math.min(12, 5+(t.snr||0)/5));
379	
380	            if(!targetTrailHistory[t.id]) targetTrailHistory[t.id] = [];
381	            targetTrailHistory[t.id].push([lat,lon]);
382	            if(targetTrailHistory[t.id].length > maxTrailLength)
383	                targetTrailHistory[t.id].shift();
384	
385	            if(targetMarkers[t.id]) {{
386	                targetMarkers[t.id].setLatLng([lat,lon]);
387	                targetMarkers[t.id].setStyle({{
388	                    fillColor:color, color:'white', radius:radius
389	                }});
390	                if(targetTrails[t.id]) {{
391	                    targetTrails[t.id].setLatLngs(targetTrailHistory[t.id]);
392	                    targetTrails[t.id].setStyle({{ color:color }});
393	                }}
394	            }} else {{
395	                var marker = L.circleMarker([lat,lon], {{
396	                    radius:radius, fillColor:color, color:'white',
397	                    weight:2, opacity:1, fillOpacity:0.9
398	                }}).addTo(map);
399	                marker.on(
400	                    'click',
401	                    (function(id){{
402	                        return function(){{ if(bridge) bridge.onMarkerClick(id); }};
403	                    }})(t.id)
404	                );
405	                targetMarkers[t.id] = marker;
406	                if(showTrails) {{
407	                    targetTrails[t.id] = L.polyline(targetTrailHistory[t.id], {{
408	                        color:color, weight:3, opacity:0.7,
409	                        lineCap:'round', lineJoin:'round'
410	                    }}).addTo(map);
411	                }}
412	            }}
413	            updateTargetPopup(t);
414	        }});
415	
416	        for(var id in targetMarkers) {{
417	            if(!currentIds[id]) {{
418	                map.removeLayer(targetMarkers[id]); delete targetMarkers[id];
419	                if(targetTrails[id]) {{
420	                    map.removeLayer(targetTrails[id]);
421	                    delete targetTrails[id];
422	                }}
423	                delete targetTrailHistory[id];
424	            }}
425	        }}
426	    }} catch(e) {{
427	        if(bridge) bridge.logFromJS('updateTargets ERROR: '+e.message);
428	    }}
429	}}
