431	function updateTargetPopup(t) {{
432	    if(!targetMarkers[t.id]) return;
433	    var sc = t.velocity>1
434	        ? 'status-approaching'
435	        : (t.velocity<-1 ? 'status-receding' : 'status-stationary');
436	    var st = t.velocity>1?'Approaching':(t.velocity<-1?'Receding':'Stationary');
437	    var rng = (typeof t.range === 'number') ? t.range.toFixed(1) : '?';
438	    var vel = (typeof t.velocity === 'number') ? t.velocity.toFixed(1) : '?';
439	    var az  = (typeof t.azimuth === 'number') ? t.azimuth.toFixed(1) : '?';
440	    var el  = (typeof t.elevation === 'number') ? t.elevation.toFixed(1) : '?';
441	    var snr = (typeof t.snr === 'number') ? t.snr.toFixed(1) : '?';
442	    targetMarkers[t.id].bindPopup(
443	        '<div class="popup-title">Target #'+t.id+'</div>'+
444	        '<div class="popup-row"><span class="popup-label">Range:</span>'+
445	        '<span class="popup-value">'+rng+' m</span></div>'+
446	        '<div class="popup-row"><span class="popup-label">Velocity:</span>'+
447	        '<span class="popup-value">'+vel+' m/s</span></div>'+
448	        '<div class="popup-row"><span class="popup-label">Azimuth:</span>'+
449	        '<span class="popup-value">'+az+'&deg;</span></div>'+
450	        '<div class="popup-row"><span class="popup-label">Elevation:</span>'+
451	        '<span class="popup-value">'+el+'&deg;</span></div>'+
452	        '<div class="popup-row"><span class="popup-label">SNR:</span>'+
453	        '<span class="popup-value">'+snr+' dB</span></div>'+
454	        '<div class="popup-row"><span class="popup-label">Track:</span>'+
455	        '<span class="popup-value">'+t.track_id+'</span></div>'+
456	        '<div class="popup-row"><span class="popup-label">Status:</span>'+
457	        '<span class="popup-value '+sc+'">'+st+'</span></div>'
458	    );
459	}}
