461	function getTargetColor(v) {{
462	    if(v>50)  return '#FF1744';
463	    if(v>10)  return '#FF5252';
464	    if(v>1)   return '#FF8A65';
465	    if(v<-50) return '#1565C0';
466	    if(v<-10) return '#2196F3';
467	    if(v<-1)  return '#64B5F6';
468	    return '#9E9E9E';
469	}}
