471	function setCoverageVisible(vis) {{
472	    showCoverage = vis;
473	    if(coverageCircle) {{
474	        if(vis) coverageCircle.addTo(map); else map.removeLayer(coverageCircle);
475	    }}
476	}}
477	function setCoverageRadius(r) {{ if(coverageCircle) coverageCircle.setRadius(r); }}
478	
479	function setTrailsVisible(vis) {{
480	    showTrails = vis;
481	    if(vis) {{
482	        for(var id in targetMarkers) {{
483	            if(!targetTrails[id] && targetTrailHistory[id] && targetTrailHistory[id].length>1) {{
484	                targetTrails[id] = L.polyline(targetTrailHistory[id], {{
485	                    color:'#4CAF50', weight:3, opacity:0.7, lineCap:'round', lineJoin:'round'
486	                }}).addTo(map);
487	            }} else if(targetTrails[id]) {{
488	                targetTrails[id].addTo(map);
489	            }}
490	        }}
491	    }} else {{
492	        for(var id in targetTrails) {{ map.removeLayer(targetTrails[id]); }}
493	    }}
494	}}
495	
496	function centerOnRadar() {{ if(radarMarker) map.setView(radarMarker.getLatLng(), map.getZoom()); }}
497	
498	function fitAllTargets() {{
499	    var b = L.latLngBounds([]);
500	    if(radarMarker) b.extend(radarMarker.getLatLng());
501	    for(var id in targetMarkers) b.extend(targetMarkers[id].getLatLng());
502	    if(b.isValid()) map.fitBounds(b, {{ padding:[50,50] }});
503	}}
504	
505	function setZoom(lvl) {{ map.setZoom(lvl); }}
506	
507	document.addEventListener('DOMContentLoaded', function() {{
508	    new QWebChannel(qt.webChannelTransport, function(ch) {{
509	        bridge = ch.objects.bridge;
510	        initMap();
511	        if(bridge) bridge.onMapReady();
512	    }});
513	}});
514	</script>
515	</body>
