518	    # ---- load / helpers ----------------------------------------------------
519	
520	    def _load_map(self):
521	        # Enable remote resource access so Leaflet CDN scripts/tiles can load.
522	        settings = self._web_view.page().settings()
523	        settings.setAttribute(
524	            QWebEngineSettings.WebAttribute.LocalContentCanAccessRemoteUrls,
525	            True,
526	        )
527	        # Provide an HTTP base URL so the page has a proper origin;
528	        # without this, setHtml() defaults to about:blank which blocks
529	        # external resource loading in modern Chromium.
530	        self._web_view.setHtml(
531	            self._get_map_html(),
532	            QUrl("http://localhost/radar_map"),
533	        )
534	        logger.info("Leaflet map HTML loaded (with HTTP base URL)")
535	
536	    def _on_map_ready(self):
537	        self._status_label.setText(f"Map ready - {len(self._targets)} targets")
538	        self._status_label.setStyleSheet(f"color: {DARK_SUCCESS};")
539	        # Flush any targets that arrived before the map was ready
540	        if self._pending_targets is not None:
541	            self.set_targets(self._pending_targets)
542	            self._pending_targets = None
543	
544	    def _on_marker_clicked(self, tid: int):
545	        self.targetSelected.emit(tid)
